UPDATE `broadcast_text_locale` SET `Text_lang`='만나서 반갑소, 대영주! 인생이 참, 생각했던 것과 많이 달라졌소. 처음에는 은빛 손을 회수했고, 이젠 믿기 어렵게도 위대한 티탄 수호자 티르 님이 돌아오셨지.\n\n이렇게 아르칸티나에서 당신을 비롯해... 상상조차 어려운 일을 직접 본 사람들과 쉬고 있는 게 위안이 되는구려.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=308983 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text_lang`='빛나무 무기 배송이 왜 늦는지 알아보려고 온 건가? 그렇다면 잘 찾아왔네.\n\n황혼의 칼날단이 우리 야영지를 알아냈고, 아마니에게 강력한 빛나무 무기를 공급한다는 것도 눈치챘지. 그래서 요즘은 수시로 들이닥쳐서 일만 방해하고 있어.\n\n그 와중에 어떤 엘프 아이가 야영지에 들이닥쳐서는 여동생 얘기를 하며 고래고래 소리를 지르지 뭔가. 지금 황혼의 칼날단 상대하기도 바쁜데, 엘프 농부의 화나고 길 잃은 자식까지 돌볼 시간은 없네!\n\n나이도 어리고, 뭐든 다 안다고 착각해. 하지만 나라고 다 모르는 건 아니거든...\n\n자네가 이 두 가지 문제를 한꺼번에 해결해 줄 수 있을지도 모르겠군.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=308778 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text_lang`='너는 샬라드라실의 뿌리감시관 루이아 앞에 서 있다. 나는 이 저주받은 뿌리들을 지키며 85년을 보냈다. 내 스승께서 흙으로 돌아가기 전 그렇게 했던 것처럼 말이다.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=308501 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text1_lang`='칸자는... 남달라.\n\n어렸을 때는 말을 하지도 않고, 웃지도 않고, 누구와 눈도 마주치려 하지 않았지.\n\n하지만 내 어머니와 칸자의 아버지, 쌍둥이 자매의 도움으로 조금씩 말도 하고, 놀기도 하고, 또래 아이들처럼 지낼 수 있게 되었어.\n\n그런데 내 어머니가 세상을 떠났고, 아버지는 일로 점점 더 바빠졌고, 자나카는 혈액 질병으로 목숨을 잃었지.\n\n자나카가 떠난 이후로, 칸자는 다시 입을 닫았어. 지금껏 시간을 주고 있었는데... 벌써 3년이 흘렀군.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=307197 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text1_lang`='그래도 썩은가지한테 잡히진 않았고, 아버지도 무사히 돌아오셨으니 다행이군.\n\n우리 작은 가족은 이미 겪을 만큼 겪었어. 더는 안 돼.\n\n그나저나, 칸자는 또 어디 갔지?', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=306852 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text1_lang`='칸자가 간 방향...\n\n그리고 챙겨 간 물건들...\n\n필로를 부를 수 있는 건 아이뿐이고, 아이의 마음으로 불러야 해.\n\n찻주전자, 소풍 바구니... 칸자는 필로랑 놀고 싶었던 거야.\n\n그런데 찻주전자는 깨졌고, 음식을 가득 담은 바구니는 떨어뜨려 버렸으니, 이젠 어쩌려는지...', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=306851 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text1_lang`='흠... 코비스라...', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=305742 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text_lang`='<종이들의 위치와 주변 발자국을 보면 누군가 급히 자리를 떴고, 여러 멀록에게 쫓긴 것으로 보입니다.>\n\n심해지느러미가 벌인 토착민 습격은 계획 중 일부에 불과했던 것 같다. 또 다른 목표는 아탈아바시의 무덤이었다.\n\n심해지느러미는 지금까지 멀록에게서 볼 수 없었던 강력한 강령술을 갖추고 있다. 트롤의 유해를 되살려 언데드로 만들 정도니까! 이 힘을 어디서 배운 걸까? 근처의 썩은가지 트롤에게서 전수받은 걸지도 모르겠다.\n\n어쨌든, 이건 단순한 습격이 아니다. 심해지느러미는 언데드 군대를 일으키고 있다. 목적이 무엇인지는 아직 알 수 없다.\n\n<발자국은 북서쪽으로 이어져 있습니다.>', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=305450 AND `locale`='koKR');
