UPDATE `broadcast_text_locale` SET `Text_lang`='자네 딸 아마시에게 주는 건 어떻겠나? 온 마을 사람들에게 새로운 요리를 먹이고 있던데.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=288359 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text_lang`='이번만큼은 저도 멜레도어의 말에 동의합니다. 죄송하지만, 저도 돕지 않겠습니다.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=288133 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text_lang`='...일지?!', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=287914 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text_lang`='토르톨란은 당분간 머물러도 되네. 나만큼이나 고집이 센 친구구먼!', `Text1_lang`='토르톨란은 당분간 머물러도 되네. 나만큼이나 고집이 센 친구구먼!', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=287852 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text_lang`='토르톨란의 말이 진심이었다고? 정말 얼굴을 내밀었단 말인가?\n\n<호탕하게 웃는 장로 렌젠>\n\n편지를 그렇게도 보냈으니! 정작 난 무시로 일관했지만. 그러다 결국 친구에게 허락만 기다리지 말고 하고 싶은 걸 하라고 했네. 그래도 기다리겠다고 하더군!\n\n어찌 거절하겠나? 그래서 \"허락 편지\"를 보냈네. 몇 년 동안 한 번도 주지 않았던 건데!\n\n결정을 존중하겠네. 자고로 탐구자는 스스로 원하는 길을 갈 자유가 있지. 어차피 마른나무껍질이 토르톨란 손님들을 지켜볼 게야. 이 땅을 찾은 방문객한테는 다 그렇게 하고 있으니.', `Text1_lang`='토르톨란의 말이 진심이었다고? 정말 얼굴을 내밀었단 말인가?\n\n<호탕하게 웃는 장로 렌젠>\n\n편지를 그렇게도 보냈으니! 정작 난 무시로 일관했지만. 그러다 결국 친구에게 허락만 기다리지 말고 하고 싶은 걸 하라고 했네. 그래도 기다리겠다고 하더군!\n\n어찌 거절하겠나? 그래서 \"허락 편지\"를 보냈네. 몇 년 동안 한 번도 주지 않았던 건데!\n\n결정을 존중하겠네. 자고로 탐구자는 스스로 원하는 길을 갈 자유가 있지. 어차피 마른나무껍질이 토르톨란 손님들을 지켜볼 게야. 이 땅을 찾은 방문객한테는 다 그렇게 하고 있으니.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=287847 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text_lang`='다음 달에 사냥을 주관할 생각이야. 혹시 함께할 수 있겠어?', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=287600 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text_lang`='토룬도가 보낸 건가? 빛나무 무기 배송이 왜 늦는지 알아보라고? 그렇다면 잘 찾아왔네.\n\n황혼의 칼날단이 우리 야영지를 알아냈고, 아마니에게 강력한 빛나무 무기를 공급한다는 것도 눈치챘지. 그래서 요즘은 수시로 들이닥쳐서 일만 방해하고 있어.\n\n그 와중에 어떤 엘프 아이가 야영지에 들이닥쳐서는 여동생 얘기를 하며 고래고래 소리를 지르지 뭔가. 지금 황혼의 칼날단 상대하기도 바쁜데, 엘프 농부의 화나고 길 잃은 자식까지 돌볼 시간은 없네!\n\n나이도 어리고, 뭐든 다 안다고 착각해. 하지만 나라고 다 모르는 건 아니거든...\n\n자네가 이 두 가지 문제를 한꺼번에 해결해 줄 수 있을지도 모르겠군.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=286257 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text1_lang`='<뾰족한 이를 드러내며 환히 웃는 마르직스>', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=247439 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text_lang`='명심하시오. 눈앞에서 폭발한다면 제대로 찾았단 뜻이오!', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=239474 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `locale`='koKR' AND `ID` IN (273277,272911,295984));
UPDATE `broadcast_text_locale` SET `Text1_lang`='바텐더가 독한 술로 들겠냐고 묻더군. 이미 죽은 몸인데, 좀 독하게 마신다고 뭐가 달라지겠나.\n\n<주변을 훑으며 잔을 천천히 한 모금 마시는 릴리안>\n\n이곳은 시끄럽고, 탄 맥주 냄새가 가득하네... 그런데 기묘하게도 고향처럼 푸근해. 더 이상한 건, 호드와 얼라이언스 바로 옆에 앉아 있으면서도 묘한 평온을 느낀다는 걸세. 이곳의 활기찬 분위기는 특이하지만, 참 반갑구먼.\n\n우리 모두가 공유하는 건 단 하나, 쉴 수 있는 순간은 천금과도 같다는 걸세. 쉽게 사라지니까 더욱더 열심히 붙들게 되지.\n\n혹시 술에서 독 맛이 난다면, 내 탓은 아닐세. 오늘은 정말 쉬고 싶거든.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=308821 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text1_lang`='나는 발리라 생귀나르라고 해. 스스로 길을 개척하는 블러드 엘프지.\n\n내 과거는... 복잡해. 그래도 믿을 건 언제나 나 자신이었어.\n\n나는 린 가문과 함께 싸웠고, 지금은 실버문과 섭정의 아군이야.\n\n나는 누구의 하수인도, 첩자도 아니야. 내가 신뢰하는 이들의 동료일 뿐이지.\n\n그 정도로 충분하다면, 언젠가 우리도 함께할 기회가 올 거야.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=301657 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text1_lang`='그럼 가보겠다. 동족을 위해, 그리고 외숙부님을 위해서요.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=299055 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text_lang`='한낱 필멸자가 만든 무기는 잘아타스 님의 위대한 계획에 흠집도 내지 못한다!', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=297004 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text_lang`='아마니를 파괴하라! 부숴라! 잘아타스 님을 위해 혼돈을 뿌려라!', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=296930 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text1_lang`='그자들은 힘이 부족했죠. 우리가 두번 다 짓눌러버렸고요.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=295985 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text1_lang`='이미 마법학자에, 기사단에, 무기까지 다 가져갔으면서, 이젠 음식도 내놓으라고?', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=295318 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text_lang`='저는 리 리의 오빠 스싸이라고 합니다. 직접 맞이해 드리지 못한 게 아쉽네요. 이젠 모두 우리만 기다리고 있는 걸까요?\n\n며칠 전 축제를 준비하려고 우쏭 마을에 갔는데, 가장 중요한 폭죽이 사라졌더군요! 집에 돌아와 찾아봤지만 아직도 못 찾고 있네요. 시간이 얼마 남지 않았으니 그냥 없는 대로 해야 할지도 모릅니다.\n\n<이마의 땀을 훔치는 스싸이>\n\n리 리의 친구를 만나 정말 반갑습니다. 마지막으로 동생을 본 지 오래된 터라, 풀어야 할 회포가 산더미예요. 물론 대부분은 리 리의 이야기를 듣는 시간이겠지만요. 전 집을 떠나 지금은 아침 바람 마을에서 살고 있습니다. 호숫가에 자리한 정말 아름다운 곳이죠.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=294283 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text_lang`='여기 있었군, 파올! 우릴 왜 이런 황량한 땅으로 데려온 건가?', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=294167 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text_lang`='물론이죠, 어둠에 물든 동족이여.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=293822 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text1_lang`='전 외숙부님 얘기를 듣는 걸 좋아했어요. 사실일까 궁금하기도 했지만요.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=291856 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text1_lang`='아킬존, 할라지, 잔알라이, 날로라크에 대한 이야기와... 그들이 우릴 어떻게 지켜줬는지 기억합니다.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=291853 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text1_lang`='화물이 하나 더 남긴 했는데, 거의 끝나 간다.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=291585 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text1_lang`='태양샘에서 터져 나온 마력은... 제가 지금껏 봐온 어떤 마법보다도 강력했습니다. 참고로 전 마법을 수련한 기간이 결코 짧지 않아요. 저 군대가 우릴 지켜주러 온 거라는데, 마력 쇄도를 일으킨 것도 저들이라고 들었습니다! 뭘 제대로 알고 건드리기나 하는 걸까요?', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=290937 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text_lang`='이 괴물은 강대한 힘을 지녔음에도, 고통에 휩싸여 있었습니다. 저도 분노에 삼켜졌을 때 고통에 휘둘려 폭발했지요. 공허도 빛과 같은 걸까요?', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=288987 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text_lang`='반갑네, $p!\n\n이 어둠과 공허 속에서도 빛은 더욱 강하게 타오르고 있네. 언데드인 내 몸엔 언제나 그 고통이 따르지만, 포식의 군단은 나보다도 훨씬 더 그 분노에 취약하지.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=283177 AND `locale`='koKR');
UPDATE `broadcast_text_locale` SET `Text1_lang`='같이 어머니를 기억할 수 있어서 기뻐요.', `VerifiedBuild`=67186 WHERE (`VerifiedBuild`>0 AND `ID`=273965 AND `locale`='koKR');
