INSERT INTO `currency_types_locale` (`ID`, `locale`, `Name_lang`, `Description_lang`, `VerifiedBuild`) VALUES
(3513, 'koKR', '성운의 공허핵', '한밤 1 시즌 공격대에서 강력한 적을 처치하거나, 신화+ 던전, 풍요로운 구렁, 악몽 난이도 사냥감 추적 완료 시 강력한 장비로 변환할 수 있습니다.', 67186),
(3347, 'koKR', '신화 여명문장', '한밤 1 시즌 기간에 신화 장비를 최대 아이템 레벨 276~289로 강화하는 데 사용됩니다.\n\n제작에 사용 시 완성되는 아이템의 아이템 레벨을 품질에 따라 272~285로 설정합니다.\n\n아래 활동을 완료하여 획득할 수 있습니다.\n\n- 신화 공허첨탑, 꿈의 균열, 쿠엘다나스 진격로\n- 9 레벨 이상의 신화 쐐기돌 던전', 67186),
(3346, 'koKR', '영웅 여명문장', '한밤 1 시즌 기간에 영웅 장비를 최대 아이템 레벨 263~276으로 강화하는 데 사용됩니다. 아래 활동을 완료하여 획득할 수 있습니다.\n\n- 영웅 공허첨탑, 꿈의 균열, 쿠엘다나스 진격로\n- 4~8 레벨 신화 쐐기돌 던전\n- 11 레벨 구렁\n- 8 레벨 이상의 보물 추적자의 은혜\n- 사냥감 추적 (악몽)', 67186),
(3345, 'koKR', '영웅 여명문장', '한밤 1 시즌 기간에 영웅 장비를 최대 아이템 레벨 263~276으로 강화하는 데 사용됩니다.\n\n제작에 사용 시 완성되는 아이템의 아이템 레벨을 품질에 따라 259~272로 설정합니다.\n\n아래 활동을 완료하여 획득할 수 있습니다.\n\n- 영웅 공허첨탑, 꿈의 균열, 쿠엘다나스 진격로\n- 4~8 레벨 신화 쐐기돌 던전\n- 11 레벨 구렁\n- 8 레벨 이상의 보물 추적자의 은혜\n- 사냥감 추적 (악몽)', 67186),
(3344, 'koKR', '챔피언 여명문장', '한밤 1 시즌 기간에 챔피언 장비를 최대 아이템 레벨 250~263으로 강화하는 데 사용됩니다. 아래 활동을 완료하여 획득할 수 있습니다.\n\n- 주간 야외 이벤트\n- 일반 공허첨탑, 꿈의 균열, 쿠엘다나스 진격로\n- 신화 시즌 던전\n- 2~3 레벨 신화 쐐기돌 던전\n- 7~10 레벨 구렁\n- 6~7 레벨 보물 추적자의 은혜\n- 사냥감 추적 (악몽)', 67186),
(3343, 'koKR', '챔피언 여명문장', '한밤 1 시즌 기간에 챔피언 장비를 최대 아이템 레벨 250~263으로 강화하는 데 사용됩니다. 아래 활동을 완료하여 획득할 수 있습니다.\n\n- 주간 야외 이벤트\n- 일반 공허첨탑, 꿈의 균열, 쿠엘다나스 진격로\n- 신화 시즌 던전\n- 2~3 레벨 신화 쐐기돌 던전\n- 7~10 레벨 구렁\n- 6~7 레벨 보물 추적자의 은혜\n- 사냥감 추적 (악몽)', 67186),
(3342, 'koKR', '노련가 여명문장', '한밤 1 시즌 기간에 노련가 장비를 최대 아이템 레벨 237~250으로 강화하는 데 사용됩니다. 아래 활동을 완료하여 획득할 수 있습니다.\n\n- 반복 가능 야외 이벤트\n- 공격대 찾기 공허첨탑, 꿈의 균열, 쿠엘다나스 진격로\n- 영웅 시즌 던전\n- 5~6 레벨 구렁\n- 4~5 레벨 보물 추적자의 은혜\n- 사냥감 추적 (어려움)', 67186),
(3341, 'koKR', '노련가 여명문장', '한밤 1 시즌 기간에 노련가 장비를 최대 아이템 레벨 237~250으로 강화하는 데 사용됩니다.\n\n제작에 사용 시 완성되는 아이템의 아이템 레벨을 품질에 따라 233~246으로 설정합니다.\n\n아래 활동을 완료하여 획득할 수 있습니다.\n\n- 반복 가능 야외 이벤트\n- 공격대 찾기 공허첨탑, 꿈의 균열, 쿠엘다나스 진격로\n- 영웅 시즌 던전\n- 5~6 레벨 구렁\n- 4~5 레벨 보물 추적자의 은혜\n- 사냥감 추적 (어려움)', 67186),
(3418, 'koKR', '성운의 공허핵', '한밤 1 시즌 공격대에서 강력한 적을 처치하거나, 신화+ 던전, 풍요로운 구렁, 악몽 난이도 사냥감 추적 완료 시 강력한 장비로 변환할 수 있습니다.', 67186),
(3391, 'koKR', '모험가 여명문장', '한밤 1 시즌 기간에 모험가 장비를 최대 아이템 레벨 224~237로 강화하는 데 사용됩니다. 아래 활동을 완료하여 획득할 수 있습니다.\n\n- 반복 가능 야외 이벤트\n- 4 레벨 구렁\n- 사냥감 추적 (일반)', 67186),
