(264323, 'koKR', '수집품에 보유하고 있지 않은 꾸미기용 공허에 물든 무기가 들어 있습니다.', '', '', '', '공허에 물든 무기 보관함', 67186),
(264322, 'koKR', '수집품에 보유하고 있지 않은 꾸미기용 공허에 물든 장화가 들어 있습니다.', '', '', '', '공허에 물든 장화 보관함', 67186),
(264321, 'koKR', '수집품에 보유하고 있지 않은 꾸미기용 공허에 물든 다리보호구가 들어 있습니다.', '', '', '', '공허에 물든 다리보호구 보관함', 67186),
(264320, 'koKR', '수집품에 보유하고 있지 않은 꾸미기용 공허에 물든 허리띠가 들어 있습니다.', '', '', '', '공허에 물든 허리띠 보관함', 67186),
(264319, 'koKR', '수집품에 보유하고 있지 않은 꾸미기용 공허에 물든 장갑이 들어 있습니다.', '', '', '', '공허에 물든 장갑 보관함', 67186),
(264318, 'koKR', '수집품에 보유하고 있지 않은 꾸미기용 공허에 물든 팔보호구가 들어 있습니다.', '', '', '', '공허에 물든 팔보호구 보관함', 67186),
(264317, 'koKR', '수집품에 보유하고 있지 않은 꾸미기용 공허에 물든 가슴보호구가 들어 있습니다.', '', '', '', '공허에 물든 가슴보호구 보관함', 67186),
(264316, 'koKR', '수집품에 보유하고 있지 않은 꾸미기용 공허에 물든 망토가 들어 있습니다.', '', '', '', '공허에 물든 망토 보관함', 67186),
(264315, 'koKR', '수집품에 보유하고 있지 않은 꾸미기용 공허에 물든 어깨보호구가 들어 있습니다.', '', '', '', '공허에 물든 어깨보호구 보관함', 67186),
(264314, 'koKR', '수집품에 보유하고 있지 않은 꾸미기용 공허에 물든 투구가 들어 있습니다.', '', '', '', '공허에 물든 머리보호구 보관함', 67186),
(256700, 'koKR', '아제로스의 축복 인장 만드는 법을 배웁니다.', '', '', '', '디자인: 아제로스의 축복 인장', 67186),
(250445, 'koKR', '', '', '', '', '풍요의 메아리: 마법부여', 67186),
(250360, 'koKR', '', '', '', '', '풍요의 메아리: 무두질', 67186),
(250443, 'koKR', '', '', '', '', '풍요의 메아리: 약초채집', 67186),
(272125, 'koKR', '골드와 공허불빛 이회토가 들어 있으며, 현재 전문화에 알맞은 아이템을 획득합니다. 야전에서 세운 공로를 인정하는 의미로 지급됐습니다.', '', '', '', '신병의 보관함', 67186),
(263286, 'koKR', '', '', '', '', '개조된 버섯전사 방패', 67186),
(273307, 'koKR', '용감한 사업가가 착즙한 산뜻한 음료입니다! 설탕 결정이 들어 있어 반짝거린답니다... 아니지, 마나 결정인가?', '', '', '', '용감한 레모네이드가 든 병', 67186),
(265790, 'koKR', '영웅 및 신화 여명문장 10개가 들어 있는 주머니입니다.', '', '', '', '여명문장 보관함', 67186),
(246753, 'koKR', '', '', '', '', '영광스러운 신화 여명문장 묶음', 67186),
(255627, 'koKR', '', '', '', '', '우주를 호령하는 검투사의 망치', 67186),
