(253582, 'koKR', '', '', '', '', '송곳니지느러미 도리깨', 67186);
INSERT INTO `journal_encounter_section_locale` (`ID`, `locale`, `Title_lang`, `BodyText_lang`, `VerifiedBuild`) VALUES
(32672, 'koKR', '방어 담당', '$bullet; 비축광은 |cFF2959D3|Hspell:1235072|h[자원 활용책]|h|r 지속시간 동안 가장 가까운 자원 더미를 모읍니다.\n$bullet; 썩은 버섯은 접촉 시 |cFF2959D3|Hspell:1234846|h[독성 포자]|h|r를 부여하며, |cFF2959D3|Hspell:1245593|h[부패의 파열]|h|r 폭발을 방지합니다.\n$bullet; |cFF2959D3|Hspell:1234681|h[게걸스러운 고함]|h|r과 |cFF2959D3|Hspell:1235125|h[풍족한 고함]|h|r은 모든 플레이어에게 막대한 피해를 입힙니다.', 67186),
(32669, 'koKR', '개요', '비축광은 수단과 방법을 가리지 않고 도둑을 방지하려고 하며, 생명력이 90%, 60%, 30% 이하로 떨어지면 |cFF2959D3|Hspell:1235072|h[자원 활용책]|h|r을 시전하여 능력을 하나 강화합니다.\n\n기력이 100에 도달하면 |cFF2959D3|Hspell:1234233|h[더럽혀진 보급품]|h|r을 전장에 던져 12초 동안 썩은 버섯이 자라나게 합니다. 버섯과 접촉 시 |cFF2959D3|Hspell:1234846|h[독성 포자]|h|r가 부여되고 버섯은 파괴되며, |cFF2959D3|Hspell:1245593|h[부패의 파열]|h|r이 방지됩니다.', 67186),
(31527, 'koKR', '금지된 화물', '눈에 띄지 않도록 잘 숨겨져 있던 화물입니다. 훌륭한 엄폐물이 되어줍니다.', 67186),
(31282, 'koKR', '방어 담당', '$bullet; 키스티아는 냠냠이에게 |cFF2959D3|Hspell:1230289|h[부정한 주입]|h|r을 걸어 플레이어를 적대하게 만듭니다.\n$bullet; 냠냠이의 |cFF2959D3|Hspell:1253811|h[지옥 분사]|h|r를 피해야 합니다.\n$bullet; 키스티아의 |cFF2959D3|Hspell:1264095|h[환영 복제]|h|r를 방해해야 합니다.', 67186),
(31281, 'koKR', '치유 담당', '$bullet; 키스티아는 냠냠이에게 |cFF2959D3|Hspell:1230289|h[부정한 주입]|h|r을 걸어 플레이어를 적대하게 만듭니다.\n$bullet; 냠냠이의 |cFF2959D3|Hspell:1253811|h[지옥 분사]|h|r를 피해야 합니다.\n$bullet; 키스티아는 |cFF2959D3|Hspell:1265412|h[불안정화]|h|r에 걸리면 모든 플레이어에게 막대한 피해를 입힙니다.', 67186),
(31280, 'koKR', '공격 담당', '$bullet; 키스티아는 냠냠이에게 |cFF2959D3|Hspell:1230289|h[부정한 주입]|h|r을 걸어 플레이어를 적대하게 만듭니다.\n$bullet; 냠냠이의 |cFF2959D3|Hspell:1253811|h[지옥 분사]|h|r를 피해야 합니다.\n$bullet; 키스티아의 |cFF2959D3|Hspell:1264095|h[환영 복제]|h|r를 방해해야 합니다.', 67186),
(35862, 'koKR', 'Section 18', '', 67186),
(35353, 'koKR', '17구역', '|n\nBy speaking with Lindormi near The Timeways portal or at the end of a Keystone Dungeon, characters with a tank specialization can enable |cFF2959D3|Hspell:1295986|h[Lindormi\'s Glow]|h|r when |cFF2959D3|Hspell:1278156|h[Lindormi\'s Guidance]|h|r is inactive.', 67186),
(34751, 'koKR', '17구역', '', 67186),
(34733, 'koKR', '잘아타스의 기만', '잘아타스가 플레이어를 배신해 자신이 베푼 혜택을 박탈하며, 사망 시 남은 시간이 15초만큼 차감되게 합니다.', 67186),
(34732, 'koKR', '경화', '우두머리가 아닌 적의 생명력이 20%만큼, 공격력이 20%만큼 증가합니다.', 67186),
(34731, 'koKR', '폭군', '우두머리의 생명력이 25%만큼 증가합니다. 우두머리와 그 하수인의 공격력이 최대 15%만큼 증가합니다.', 67186),
(34730, 'koKR', '폭군 및 경화', '이 속성은 신화 쐐기돌 던전 내 적을 추가로 강화합니다. 신화 7 레벨에 하나, 10 레벨에 다른 하나가 활성화됩니다. 매주 순환됩니다.', 67186),
(34727, 'koKR', '잘아타스의 제안: 탐식', '', 67186),
(34725, 'koKR', '잘아타스의 제안: 공허결속', '', 67186),
(34722, 'koKR', '잘아타스의 제안: 맥동성', '', 67186),
(34720, 'koKR', '신화 6 레벨', '$bullet;|cFF2959D3|Hspell:1284818|h[린도르미의 인도]|h|r가 제거됩니다.\n\n방어 담당 전문화를 가진 캐릭터는 시간의 길 차원문이나 쐐기돌 던전 종료 지점에서 린도르미에게 말을 걸어 |cFF2959D3|Hspell:1295986|h[린도르미의 광채]|h|r를 부여받을 수 있습니다. 이 효과는 지속적으로 적 병력을 강조 표시합니다.', 67186),
(35809, 'koKR', 'Section 158', '', 67186),
