INSERT INTO `mail_template_locale` (`ID`, `locale`, `Body_lang`, `VerifiedBuild`) VALUES
(659, 'koKR', '반갑네, 수행사제여!\n\n영광스러운 풍요로 넘실대는 이 영역의 경이를 목도하게나! 끝없이 솟구치고 부풀어 오르며, 그 어떤 억압이나 굴레도 거부하지!\n\n이 몸의 신성을 향한 자네의 헌신을 갸륵하게 여겨, 보답으로 작은 자비를 베풀기로 했네. 그러므로 이번에 순수한 풍요를 하사하겠네!\n\n참, 기특한 수행사제여, 명심할 것이 있네. 융합된 활력과 같은 특정한 공물들은 이제 다른 상인들을 통해서도 유통될 걸세. 무슨 말이냐고? 자네의 여정이 줄아만 심연 근처로 이어진다면, 필경 그 귀한 것들을 발견하게 될 거란 얘기라네.\n\n자네의 앞길에 경이로운 수확이 함께하기를 바라네.\n\n- 풍요의 로아 둔둔', 67186);
