INSERT INTO `trait_definition_locale` (`ID`, `locale`, `OverrideName_lang`, `OverrideSubtext_lang`, `OverrideDescription_lang`, `VerifiedBuild`) VALUES
(137688, 'koKR', '꼼꼼한 복수 제작', '', '마법부여 행렬을 개선하여 환영 또는 소비용품 제작 시 추가로 물품을 생산할 확률을 증가시킵니다. 추가로 해당 전문화 점수당 $en1|1이;가; $ev1만큼 증가합니다.', 67186),
(137685, 'koKR', '', '', '소비용품 제작 시 복수 제작의 효과로 최대 $ev1%의 물품을 추가로 만듭니다.', 67186),
(137681, 'koKR', '', '', '소비용품 제작 시 복수 제작의 효과로 최대 $ev1%의 물품을 추가로 만듭니다.', 67186),
(133669, 'koKR', '', '', '합금 제작 시 $en1|1이;가; $ev1만큼 증가합니다.|n|n합금 제작 시 마무리 재료를 사용할 수 있도록 합니다.', 67186);
